// categories_extracted.json structure:
// [
//   {
//     name: "Sữa bột cao cấp",
//     url: "https://concung.com/sua-bot-101586.html",
//     children: [
//       { name: "Sữa Mỹ", url: "...", children: [] },
//       ...
//     ]
//   }
// ]

const data = $input.first().json;

// Utility: slugify
function toSlug(str) {
  return str
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .trim();
}

// Utility: extract slug from URL
function urlToSlug(url) {
  if (!url) return '';
  const parts = url.replace('https://concung.com/', '').replace('http://concung.com/', '').split('.html')[0];
  return toSlug(parts);
}

// Flatten all categories
let categoryId = 1;
let rows = [];

for (const parent of data) {
  const parentSlug = urlToSlug(parent.url);
  const parentId = categoryId++;

  // Level 1: Parent category
  rows.push({
    category_id: parentId,
    created_at: new Date().toISOString(),
    display_order: 1,
    description: '',
    category_image_url: '',
    is_active: true,
    name: parent.name.trim(),
    slug: parentSlug,
    category_url: parent.url,
    parent_slug: '',
    parent_id: 0,
    level: 1
  });

  // Level 2: Children
  for (const child of (parent.children || [])) {
    const childSlug = urlToSlug(child.url);
    const childId = categoryId++;

    rows.push({
      category_id: childId,
      created_at: new Date().toISOString(),
      display_order: 2,
      description: '',
      category_image_url: '',
      is_active: true,
      name: child.name.trim(),
      slug: childSlug,
      category_url: child.url,
      parent_slug: parentSlug,
      parent_id: parentId,
      level: 2
    });

    // Level 3: Grandchildren
    for (const grandchild of (child.children || [])) {
      const grandchildSlug = urlToSlug(grandchild.url);
      const grandchildId = categoryId++;

      rows.push({
        category_id: grandchildId,
        created_at: new Date().toISOString(),
        display_order: 3,
        description: '',
        category_image_url: '',
        is_active: true,
        name: grandchild.name.trim(),
        slug: grandchildSlug,
        category_url: grandchild.url,
        parent_slug: childSlug,
        parent_id: childId,
        level: 3
      });
    }
  }
}

// Remove internal 'level' field for final output
const finalRows = rows.map(r => {
  const { level, ...out } = r;
  return out;
});

return finalRows.map(r => ({ json: r }));

// Output JSON for API
const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    // Ensure proper types
    category_id: Number(item.json.category_id),
    display_order: Number(item.json.display_order),
    is_active: item.json.is_active === true,
    parent_id: Number(item.json.parent_id)
  }
}));
